    data = [1, 2, 3, 4, 5]
    print(f'Input: {data}')
    print(f'Size: {len(data)}')
    print(f'Contains 3: {3 in data}')

if __name__ == '__main__':
    demonstrate()
```

## Session 3: Async JavaScript


```mermaid
graph TB
    CS[Call Stack<br/>LIFO] -->|empty?| EL[Event Loop]
    EL -->|check| MQ[Microtask Queue<br/>Promise.then, queueMicrotask]
    EL -->|then check| TQ[Task Queue<br/>setTimeout, I/O, DOM events]
    MQ -->|dequeue| CS
    TQ -->|dequeue| CS
    WA[Web APIs<br/>setTimeout, fetch, DOM] -->|callback ready| TQ
    WA -->|promise resolved| MQ
```


JavaScript is single-threaded. Asynchronous operations rely on the event loop, Web APIs, and a queue system to avoid blocking the main thread.

### The Event Loop Architecture

```
┌─────────────────────────────────────────────────┐
│                  Call Stack                     │
│  main() → fetchData() → processResponse() ...  │
└──────────────────┬──────────────────────────────┘
                   │ (when empty, event loop picks next)
┌──────────────────▼──────────────────────────────┐
│            Microtask Queue                      │
│  Promise.then, queueMicrotask, MutationObserver │
│  (ALL drained before next macrotask)            │
└──────────────────┬──────────────────────────────┘
┌──────────────────▼──────────────────────────────┐
│             Task Queue (Macrotasks)             │
│  setTimeout, setInterval, I/O, UI events        │
└─────────────────────────────────────────────────┘
```

```javascript
// Classic event loop question — predict the output order
console.log('1');                          // sync

setTimeout(() => console.log('2'), 0);    // macrotask

Promise.resolve().then(() => {
  console.log('3');                        // microtask
  Promise.resolve().then(() => console.log('4')); // nested microtask
});

console.log('5');                          // sync

// Output: 1, 5, 3, 4, 2
// Explanation: sync first (1, 5), then ALL microtasks (3, 4), then macrotask (2)
```

### Callbacks and Callback Hell

```javascript
// Callback pattern — leads to pyramid of doom
getUser(userId, (err, user) => {
  if (err) return handleError(err);
  getOrders(user.id, (err, orders) => {
    if (err) return handleError(err);
    getOrderDetails(orders[0].id, (err, details) => {
      if (err) return handleError(err);
      render(user, orders, details); // deeply nested
    });
  });
});
```

### Promises

```javascript
// Promise creation
function delay(ms) {
  return new Promise((resolve, reject) => {
    if (ms < 0) reject(new Error('Negative delay'));
    setTimeout(resolve, ms);
  });
}

// Chaining — flat, readable
fetchUser(userId)
  .then(user => fetchOrders(user.id))
  .then(orders => fetchDetails(orders[0].id))
  .then(details => render(details))
  .catch(err => console.error('Pipeline failed:', err))
  .finally(() => hideSpinner());

// Promise combinators
Promise.all([fetchA(), fetchB(), fetchC()])  // all succeed or first failure
  .then(([a, b, c]) => process(a, b, c));

Promise.allSettled([fetchA(), fetchB()])     // wait for all, get all outcomes
  .then(results => results.forEach(r => {
    if (r.status === 'fulfilled') use(r.value);
    else logError(r.reason);
  }));

Promise.race([fetchPrimary(), fetchFallback()]) // first to settle wins
  .then(result => display(result));

Promise.any([fetchA(), fetchB(), fetchC()])  // first success (ignores failures)
  .then(first => display(first));
```

### async/await

```javascript
// Sequential vs parallel execution
async function sequential() {
  const a = await fetchA(); // wait for A
  const b = await fetchB(); // wait for B after A completes
  return [a, b]; // total time: timeA + timeB
}

async function parallel() {
  const [a, b] = await Promise.all([fetchA(), fetchB()]);
  return [a, b]; // total time: max(timeA, timeB)
}

// Error handling with async/await
async function loadUserData(userId: string) {
  try {
    const user = await fetchUser(userId);
    const [profile, settings] = await Promise.all([
      fetchProfile(user.id),
      fetchSettings(user.id)
    ]);
    return { user, profile, settings };
  } catch (error) {
    if (error instanceof NetworkError) {
      return loadFromCache(userId); // fallback
    }
    throw error; // re-throw unknown errors
  }
}
```

```typescript
// TypeScript: typed async with AbortController
async function fetchWithTimeout<T>(
  url: string,
  options: RequestInit = {},
  timeoutMs = 5000
): Promise<T> {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(url, {
      ...options,
      signal: controller.signal
    });
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }
    return response.json() as Promise<T>;
  } finally {
    clearTimeout(timeoutId);
  }
}

// Usage
interface UserData { id: string; name: string; }
const user = await fetchWithTimeout<UserData>('/api/user/1', {}, 3000);
```

### Interview Insight

The most common async interview question: "What is the output of this code?" followed by a mix of sync code, setTimeout, and Promise.resolve(). Always trace: (1) run all synchronous code first, (2) drain all microtasks (Promises), (3) run next macrotask (setTimeout), repeat.

### Python Implementation

```python
import queue
import threading

q = queue.Queue(maxsize=10)

def producer():
    for i in range(5):
        q.put(f'msg-{i}')
        print(f'Produced: msg-{i}')

def consumer():
    for _ in range(5):
        msg = q.get()
        print(f'Consumed: {msg}')
        q.task_done()

t1 = threading.Thread(target=producer)
t2 = threading.Thread(target=consumer)
t1.start(); t2.start()
t1.join(); t2.join()
```

## Session 4: TypeScript Essentials

TypeScript adds a static type system to JavaScript, catching errors at compile time. Mastery of its type system unlocks expressive, self-documenting, and safe code.

### Type vs Interface

```typescript
// Interface — best for objects, supports declaration merging
interface User {
  id: string;
  name: string;
  email?: string; // optional
  readonly createdAt: Date; // immutable after creation
}

// Type alias — best for unions, tuples, primitives
type ID = string | number;
type Coordinate = [number, number]; // tuple
type Status = 'active' | 'inactive' | 'pending'; // literal union

// Type can alias complex expressions; interface cannot
type ApiResponse<T> = { data: T; error: null } | { data: null; error: string };

// Declaration merging (interface only)
interface Window { myCustomProp: string; } // extends existing interface
```

### Generics

```typescript
// Generic function
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}

// Generic with constraint
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key]; // type-safe property access
}

const user = { id: '1', name: 'Alice', age: 30 };
const name = getProperty(user, 'name'); // type: string
const age  = getProperty(user, 'age');  // type: number
// getProperty(user, 'foo'); // Error: not a key of User

// Generic class
class Stack<T> {
  private items: T[] = [];
  push(item: T): void { this.items.push(item); }
  pop(): T | undefined { return this.items.pop(); }
  peek(): T | undefined { return this.items[this.items.length - 1]; }
  get size(): number { return this.items.length; }
}

const numStack = new Stack<number>();
numStack.push(1); numStack.push(2);
console.log(numStack.pop()); // 2
```

### Enums

```typescript
// Numeric enum (default)
enum Direction { Up, Down, Left, Right } // 0, 1, 2, 3
console.log(Direction.Up);    // 0
console.log(Direction[0]);    // 'Up' (reverse mapping)

// String enum (preferred — no reverse mapping issues)
enum HttpMethod {
  GET    = 'GET',
  POST   = 'POST',
  PUT    = 'PUT',
  DELETE = 'DELETE'
}

// Const enum — fully erased at compile time (zero runtime cost)
const enum Color { Red = 'RED', Green = 'GREEN', Blue = 'BLUE' }
const c: Color = Color.Red; // compiles to: const c = 'RED';

// Union type alternative (often preferred over enums in modern TS)
type Method = 'GET' | 'POST' | 'PUT' | 'DELETE';
```

### Utility Types

```typescript
interface Product {
  id: string;
  name: string;
  price: number;
  category: string;
  inStock: boolean;
}

// Partial — all properties optional
type ProductUpdate = Partial<Product>;

// Required — all properties required
type FullProduct = Required<Product>;

// Pick — select subset of keys
type ProductCard = Pick<Product, 'id' | 'name' | 'price'>;

// Omit — exclude keys
type NewProduct = Omit<Product, 'id'>;

// Record — key-value map
type CategoryMap = Record<string, Product[]>;

// ReturnType, Parameters — extract from function types
async function fetchProduct(id: string): Promise<Product> { /* ... */ return {} as Product; }
type FetchResult = Awaited<ReturnType<typeof fetchProduct>>; // Product
type FetchArgs   = Parameters<typeof fetchProduct>;         // [string]

// Conditional types
type IsArray<T> = T extends unknown[] ? true : false;
type Test1 = IsArray<number[]>; // true
type Test2 = IsArray<string>;   // false

// Mapped types
type ReadonlyProduct = { readonly [K in keyof Product]: Product[K] };
type NullableProduct = { [K in keyof Product]: Product[K] | null };
```

### Type Narrowing

```typescript
type Animal = { type: 'dog'; bark(): void } | { type: 'cat'; meow(): void };

function makeNoise(animal: Animal): void {
  if (animal.type === 'dog') {
    animal.bark(); // TypeScript knows it's a dog here
  } else {
    animal.meow(); // TypeScript knows it's a cat here
  }
}

// instanceof narrowing
function process(input: string | Error): string {
  if (input instanceof Error) return `Error: ${input.message}`;
  return input.toUpperCase();
}

// User-defined type guard
function isUser(obj: unknown): obj is User {
  return typeof obj === 'object' && obj !== null && 'id' in obj && 'name' in obj;
}
```

