## Session 5: DOM & Browser APIs

The DOM and browser APIs are the interface between JavaScript and the user interface. Understanding event propagation, efficient DOM manipulation, and modern browser APIs is essential for frontend roles.

### Event Propagation

Events propagate in three phases: capture (top → target), target, bubble (target → top). Most handlers use bubbling.

```javascript
// Event delegation — one handler for many children
const list = document.querySelector('#todo-list');

list.addEventListener('click', (event) => {
  const item = event.target.closest('.todo-item');
  if (!item) return;

  if (event.target.matches('.delete-btn')) {
    item.remove();
  } else if (event.target.matches('.complete-btn')) {
    item.classList.toggle('completed');
  }
});

// stopPropagation vs preventDefault
document.querySelector('form').addEventListener('submit', (e) => {
  e.preventDefault();  // stop form from navigating
  // e.stopPropagation(); // stop event from bubbling to parent listeners
  handleFormSubmit(e);
});

// Custom events
const cartUpdated = new CustomEvent('cart:updated', {
  detail: { itemCount: 5, total: 99.99 },
  bubbles: true
});
document.dispatchEvent(cartUpdated);
document.addEventListener('cart:updated', (e) => {
  console.log(e.detail.itemCount); // 5
});
```

### Fetch API

```javascript
// Basic fetch with error handling
async function apiRequest(url, options = {}) {
  const defaultOptions = {
    headers: { 'Content-Type': 'application/json' },
    ...options,
    body: options.body ? JSON.stringify(options.body) : undefined
  };

  const response = await fetch(url, defaultOptions);
  if (!response.ok) {
    const error = await response.json().catch(() => ({}));
    throw new Error(error.message || `HTTP ${response.status}`);
  }
  return response.json();
}

// POST with JSON body
const newUser = await apiRequest('/api/users', {
  method: 'POST',
  body: { name: 'Alice', email: 'alice@example.com' }
});

// Fetch with cancellation
const controller = new AbortController();
const timeoutId = setTimeout(() => controller.abort(), 5000);
try {
  const data = await fetch('/api/data', { signal: controller.signal });
} catch (e) {
  if (e.name === 'AbortError') console.log('Request timed out');
} finally {
