### Custom Error Classes

```javascript
// Custom error hierarchy
class AppError extends Error {
  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.name = this.constructor.name; // 'AppError'
    this.statusCode = statusCode;
    this.code = code;
    // Maintain proper stack trace in V8
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, this.constructor);
    }
  }
}

class ValidationError extends AppError {
  constructor(field, message) {
    super(message, 400, 'VALIDATION_ERROR');
    this.field = field;
  }
}

class NotFoundError extends AppError {
  constructor(resource, id) {
    super(`${resource} with id ${id} not found`, 404, 'NOT_FOUND');
    this.resource = resource;
    this.id = id;
  }
}

// Usage and instanceof checking
try {
  throw new ValidationError('email', 'Email format is invalid');
} catch (error) {
  if (error instanceof ValidationError) {
    console.log(`Field: ${error.field}, Message: ${error.message}`);
  } else if (error instanceof AppError) {
    console.log(`App error ${error.statusCode}: ${error.message}`);
  } else {
    throw error; // re-throw unexpected errors
  }
}
```

