### ES Modules (ESM)

```javascript
// math.mjs — named and default exports
export const PI = 3.14159;
export function add(a, b) { return a + b; }
export default class Calculator { /* ... */ } // default export

// main.mjs — static imports (hoisted, resolved at parse time)
import Calculator, { PI, add } from './math.mjs'; // named + default
import * as math from './math.mjs';               // namespace import
import './side-effect.mjs';                        // side-effect only

// Dynamic import (lazy loading — returns a Promise)
async function loadPlugin(name) {
  const module = await import(`./plugins/${name}.mjs`);
  return module.default;
}

