## Session 10: Performance & Memory

Performance is a first-class feature. Understanding memory leaks, optimizing event handling, and measuring real user experience are essential at senior levels.

### Common Memory Leak Patterns

```javascript
// Leak 1: Event listener not removed
class Component {
  constructor() {
    this.handleResize = this.handleResize.bind(this);
    window.addEventListener('resize', this.handleResize); // holds reference
  }
  handleResize() { /* ... */ }
  destroy() {
    window.removeEventListener('resize', this.handleResize); // fix: remove on cleanup
  }
}

// Leak 2: Closure holding large object
function processLargeData() {
  const hugeArray = new Array(1e6).fill('data');
  return function() {
    // hugeArray is closed over but only first element needed
    return hugeArray[0]; // fix: const first = hugeArray[0]; return () => first;
  };
}

// Leak 3: Detached DOM nodes
const items = [];
function addItem() {
  const el = document.createElement('div');
  document.body.appendChild(el);
  items.push(el); // even after removal, JS array holds reference
  document.body.removeChild(el);
  // fix: items.pop() after removeChild, or use WeakRef
}

// Leak 4: setInterval without clearInterval
class Timer {
  start() {
    this.id = setInterval(() => this.tick(), 1000);
  }
  stop() {
    clearInterval(this.id); // must call this
  }
  tick() { console.log('tick'); }
}
