### Debounce and Throttle

```javascript
// Debounce — delay execution until N ms after LAST call
// Use case: search-as-you-type, window resize handler
function debounce(fn, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), delay);
  };
}

const search = debounce(async (query) => {
  const results = await fetchSearchResults(query);
  renderResults(results);
}, 300);

input.addEventListener('input', (e) => search(e.target.value));

// Throttle — execute at most once per N ms
// Use case: scroll handlers, mousemove, rate limiting API calls
function throttle(fn, interval) {
  let lastTime = 0;
  return function(...args) {
    const now = Date.now();
    if (now - lastTime >= interval) {
      lastTime = now;
      return fn.apply(this, args);
    }
  };
}

const handleScroll = throttle(() => {
  updateNavbarOpacity(window.scrollY);
}, 100); // max once per 100ms

window.addEventListener('scroll', handleScroll);

// Leading + trailing debounce (more robust)
function debounceAdvanced(fn, delay, { leading = false, trailing = true } = {}) {
  let timeoutId;
  let lastArgs;
  return function(...args) {
    lastArgs = args;
    if (leading && !timeoutId) fn.apply(this, args);
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      if (trailing) fn.apply(this, lastArgs);
      timeoutId = null;
    }, delay);
  };
}
```

